import { Button, GroupBox, ScrollView } from "std-widgets.slint";

export struct OverviewUiRow {
    label: string,
    value: string,
    detail: string,
    severity: string,
}

component SeverityText inherits Text {
    in property <string> severity: "neutral";

    color: root.severity == "good" ? #8fdc8f :
        root.severity == "warning" ? #ffd166 :
        root.severity == "error" ? #ff7b7b :
        root.severity == "info" ? #8ecbff :
        root.severity == "unknown" ? #a8a8a8 :
        #d8d8d8;
}

component OverviewRows inherits Rectangle {
    in property <[OverviewUiRow]> rows;
    in property <length> label-width: 118px;

    min-height: 28px;

    VerticalLayout {
        padding: 0px;
        spacing: 5px;
        alignment: start;

        for row in root.rows: VerticalLayout {
            padding: 0px;
            spacing: 1px;
            alignment: start;

            HorizontalLayout {
                spacing: 6px;
                alignment: start;

                Text {
                    text: row.label + ":";
                    width: root.label-width;
                    font-size: 13px;
                    color: #f3f3f3;
                    horizontal-alignment: right;
                    vertical-alignment: top;
                }

                SeverityText {
                    text: row.value;
                    severity: row.severity;
                    font-size: 13px;
                    wrap: word-wrap;
                }
            }

            if row.detail != "": HorizontalLayout {
                spacing: 6px;
